#include<bits/stdc++.h>
using namespace std;

const int N = 200 + 5;

int f[N][N], n, m, t[N];

void upd(int k)
{
    for(int x = 1; x <= n; x++)
        for(int y = 1; y <= n; y++)
            f[x][y] = min(f[x][y], f[x][k] + f[k][y]);
}

int main()
{
    cin >> n >> m;
    for(int i = 1; i <= n; i++)
        cin >> t[i];
    memset(f, 0x3f, sizeof f);
    for(int i = 1; i <= m; i++)
    {
        int u, v, w;
        cin >> u >> v >> w;
        u++, v++;
        f[u][v] = f[v][u] = min(f[u][v], w);
    }
    for(int i = 1; i <= n; i++)
        f[i][i] = 0;

    int q, tmp = 0;
    cin >> q;
    while(q--)
    {
        int x, y, p;
        cin >> x >> y >> p;
        x++, y++;
        while(t[tmp + 1] <= p)
        {
            ++tmp;
            upd(tmp);
        }
        if(t[x] > p || t[y] > p || f[x][y] == 0x3f3f3f3f)
            cout << -1 << '\n';
        else cout << f[x][y] << '\n';
    }

    return 0;
}
